-- Verify import
SELECT COUNT(*) as total_projects FROM projects WHERE tenant_id = (SELECT id FROM tenants WHERE slug = 'newchandigarh');
SELECT district_name, COUNT(*) as count FROM (
  SELECT (metadata->>'district') as district_name FROM projects WHERE tenant_id = (SELECT id FROM tenants WHERE slug = 'newchandigarh')
) sub GROUP BY district_name ORDER BY count DESC;